PREFIX  xsd:  <http://www.w3.org/2001/XMLSchema#>
PREFIX  rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX  rdf:  <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
PREFIX  owl:  <http://www.w3.org/2002/07/owl#>
PREFIX  dc:   <http://purl.org/dc/elements/1.1/>

SELECT  ?question ?answer
WHERE
  { VALUES ?question { "How many languages are spoken in Colombia?"@en "Give me the capitals of all countries in Africa."@en "Which countries have more than two official languages?"@en }
    OPTIONAL
      { ?languageCountry
                  <http://www.wikidata.org/prop/direct/P31>  <http://www.wikidata.org/entity/Q34770> ;
                  ?pColombia            <http://www.wikidata.org/entity/Q739>
        FILTER ( ?question = "How many languages are spoken in Colombia?"@en )
        BIND("colombia" AS ?q)
        BIND("COUNT(?languageCountry)" AS ?c)
      }
    OPTIONAL
      { ?country  <http://www.wikidata.org/prop/direct/P31>  <http://www.wikidata.org/entity/Q6256> ;
                  <http://www.wikidata.org/prop/direct/P30>  <http://www.wikidata.org/entity/Q15> ;
                  <http://www.wikidata.org/prop/direct/P36>  ?capital
        FILTER ( ?question = "Give me the capitals of all countries in Africa."@en )
      }
    OPTIONAL
      { ?country2  <http://www.wikidata.org/prop/direct/P31>  <http://www.wikidata.org/entity/Q6256> ;
                  <http://www.wikidata.org/prop/direct/P37>  ?language2
        FILTER ( ?question = "Which countries have more than two official languages?"@en )
      }
  }
GROUP BY ?question ?answer
HAVING ( ( ( ( ?question = "How many languages are spoken in Colombia?"@en ) && ( ?answer = COUNT(?languageCountry) ) ) || ( ( ( ?question = "Give me the capitals of all countries in Africa."@en ) && bound(?capital) ) && ( ?answer = ?capital ) ) ) || ( ( ( ?question = "Which countries have more than two official languages?"@en ) && ( COUNT(?language2) > 2 ) ) && ( ?answer = ?country2 ) ) )

