PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX wd: <http://www.wikidata.org/entity/>

SELECT ?answer WHERE {
  {
    # Countries with more than two official languages
    SELECT DISTINCT ?answer WHERE {
      ?answer wdt:P31 wd:Q6256 .
      ?answer wdt:P37 ?language .
    }
    GROUP BY ?answer
    HAVING(COUNT(?language) > 2)
  }
  UNION
  {
    # Country with the most official languages
    SELECT DISTINCT ?answer WHERE {
      ?answer wdt:P31 wd:Q6256 .
      ?answer wdt:P37 ?language .
    }
    GROUP BY ?answer
    ORDER BY DESC(COUNT(?language))
    LIMIT 1
  }
  UNION
  {
    # How many programming languages are there?
    SELECT (COUNT(DISTINCT ?answer) AS ?answer) WHERE {
      ?answer wdt:P31/wdt:P279* wd:Q9143 .
    }
  }
}

SELECT DISTINCT ?result WHERE { 
  { SELECT (COUNT(DISTINCT ?movie) as ?count) WHERE { ?movie wdt:P57 wd:Q315484 . } }
  UNION
  { SELECT ?producer WHERE { 
      ?film wdt:P31 wd:Q11424.
      ?film wdt:P162 ?producer .
    } GROUP BY ?producer ORDER BY DESC(COUNT(?film)) LIMIT 1 
  }
  UNION
  { SELECT DISTINCT ?cs WHERE {
      ?cs wdt:P106 wd:Q82594 .
      ?cs wdt:P166 ?award .
      ?award wdt:P31 wd:Q19020 .
    }
  }
} LIMIT 1

